// src/services/products.ts
async function listProducts(query) {
  const conditions = [];
  if (!query.includeInactive)
    conditions.push(eq(products.isActive, true));
  if (query.search)
    conditions.push(like(products.name, `%${query.search}%`));
  return db.select().from(products).where(conditions.length ? and(...conditions) : undefined).orderBy(desc(products.createdAt));
}
async function createProduct(input) {
  const [product] = await db.insert(products).values(input).returning();
  return product;
}
async function updateProduct(id, input) {
  const [product] = await db.update(products).set(input).where(eq(products.id, id)).returning();
  if (!product) {
    throw new HTTPException(404, { message: "Product not found" });
  }
  return product;
}
async function deactivateProduct(id) {
  const [product] = await db.update(products).set({ isActive: false }).where(eq(products.id, id)).returning();
  if (!product) {
    throw new HTTPException(404, { message: "Product not found" });
  }
  return product;
}

