// src/services/reports.ts
function money(value) {
  return Number(Number(value ?? 0).toFixed(2));
}
function quantity(value) {
  return Number(Number(value ?? 0).toFixed(3));
}
async function getDailySalesReport(query) {
  const rows = await db.select({
    productId: dailyEntries.productId,
    productName: products.name,
    quantity: sql`coalesce(sum(${dailyEntries.quantity}), 0)`,
    amount: sql`coalesce(sum(${dailyEntries.quantity} * ${dailyEntries.price}), 0)`
  }).from(dailyEntries).innerJoin(products, eq(products.id, dailyEntries.productId)).where(eq(dailyEntries.entryDate, query.date)).groupBy(dailyEntries.productId, products.name);
  const [totals] = await db.select({
    totalAmount: sql`coalesce(sum(${dailyEntries.quantity} * ${dailyEntries.price}), 0)`,
    entryCount: sql`count(${dailyEntries.id})`,
    customerCount: sql`count(distinct ${dailyEntries.customerId})`
  }).from(dailyEntries).where(eq(dailyEntries.entryDate, query.date));
  return {
    date: query.date,
    products: rows.map((row) => ({
      ...row,
      quantity: Number(row.quantity),
      amount: Number(Number(row.amount).toFixed(2))
    })),
    totals: {
      totalAmount: Number(Number(totals?.totalAmount ?? 0).toFixed(2)),
      entryCount: Number(totals?.entryCount ?? 0),
      customerCount: Number(totals?.customerCount ?? 0)
    }
  };
}
async function getMonthlySalesReport(query) {
  const range = monthRange(query.month);
  const rows = await db.select({
    date: dailyEntries.entryDate,
    amount: sql`coalesce(sum(${dailyEntries.quantity} * ${dailyEntries.price}), 0)`,
    quantity: sql`coalesce(sum(${dailyEntries.quantity}), 0)`,
    entryCount: sql`count(${dailyEntries.id})`
  }).from(dailyEntries).where(and(gte(dailyEntries.entryDate, range.startDate), lte(dailyEntries.entryDate, range.endDate))).groupBy(dailyEntries.entryDate).orderBy(dailyEntries.entryDate);
  const totalAmount = rows.reduce((sum, row) => sum + Number(row.amount), 0);
  return {
    month: query.month,
    startDate: range.startDate,
    endDate: range.endDate,
    days: rows.map((row) => ({
      ...row,
      quantity: Number(row.quantity),
      amount: Number(Number(row.amount).toFixed(2)),
      entryCount: Number(row.entryCount)
    })),
    totalAmount: Number(totalAmount.toFixed(2))
  };
}
async function getCustomerSummaryReport(query) {
  const conditions = [];
  if (query.customerId)
    conditions.push(eq(customers.id, query.customerId));
  const customerRows = await db.select().from(customers).where(conditions.length ? and(...conditions) : undefined).orderBy(customers.name);
  const deliveryRows = await db.select({
    customerId: dailyEntries.customerId,
    deliveredAmount: sql`coalesce(sum(${dailyEntries.quantity} * ${dailyEntries.price}), 0)`,
    deliveredQuantity: sql`coalesce(sum(${dailyEntries.quantity}), 0)`
  }).from(dailyEntries).groupBy(dailyEntries.customerId);
  const invoiceRows = await db.select({
    customerId: invoices.customerId,
    invoiceTotal: sql`coalesce(sum(${invoices.totalAmount}), 0)`,
    paidAmount: sql`coalesce(sum(${invoices.paidAmount}), 0)`,
    pendingAmount: sql`coalesce(sum(${invoices.pendingAmount}), 0)`
  }).from(invoices).where(ne(invoices.status, "VOID")).groupBy(invoices.customerId);
  const deliveries = new Map(deliveryRows.map((row) => [row.customerId, row]));
  const invoiceTotals = new Map(invoiceRows.map((row) => [row.customerId, row]));
  return customerRows.map((customer) => {
    const delivery = deliveries.get(customer.id);
    const invoice = invoiceTotals.get(customer.id);
    return {
      customer,
      deliveredQuantity: Number(delivery?.deliveredQuantity ?? 0),
      deliveredAmount: Number(Number(delivery?.deliveredAmount ?? 0).toFixed(2)),
      invoiceTotal: Number(Number(invoice?.invoiceTotal ?? 0).toFixed(2)),
      paidAmount: Number(Number(invoice?.paidAmount ?? 0).toFixed(2)),
      pendingAmount: Number(Number(invoice?.pendingAmount ?? 0).toFixed(2))
    };
  });
}
async function getDashboardReport(query) {
  const month = monthRange(query.month);
  const customerFilter = query.customerId ? eq(dailyEntries.customerId, query.customerId) : undefined;
  const invoiceCustomerFilter = query.customerId ? eq(invoices.customerId, query.customerId) : undefined;
  const entryRangeStart = query.date < month.startDate ? query.date : month.startDate;
  const entryRangeEnd = query.date > month.endDate ? query.date : month.endDate;
  const [customerTotals] = await db.select({ totalCustomers: sql`count(${customers.id})` }).from(customers).where(query.customerId ? and(eq(customers.status, "ACTIVE"), eq(customers.id, query.customerId)) : eq(customers.status, "ACTIVE"));
  const [entryTotals] = await db.select({
    dailyAmount: sql`coalesce(sum(case when ${dailyEntries.entryDate} = ${query.date} then ${dailyEntries.quantity} * ${dailyEntries.price} else 0 end), 0)`,
    dailyEntryCount: sql`coalesce(sum(case when ${dailyEntries.entryDate} = ${query.date} then 1 else 0 end), 0)`,
    dailyCustomerCount: sql`count(distinct case when ${dailyEntries.entryDate} = ${query.date} then ${dailyEntries.customerId} end)`,
    monthlyAmount: sql`coalesce(sum(case when ${dailyEntries.entryDate} >= ${month.startDate} and ${dailyEntries.entryDate} <= ${month.endDate} then ${dailyEntries.quantity} * ${dailyEntries.price} else 0 end), 0)`,
    monthlyEntryCount: sql`coalesce(sum(case when ${dailyEntries.entryDate} >= ${month.startDate} and ${dailyEntries.entryDate} <= ${month.endDate} then 1 else 0 end), 0)`,
    monthlyCustomerCount: sql`count(distinct case when ${dailyEntries.entryDate} >= ${month.startDate} and ${dailyEntries.entryDate} <= ${month.endDate} then ${dailyEntries.customerId} end)`
  }).from(dailyEntries).where(and(gte(dailyEntries.entryDate, entryRangeStart), lte(dailyEntries.entryDate, entryRangeEnd), ...customerFilter ? [customerFilter] : []));
  const invoiceBaseConditions = [ne(invoices.status, "VOID")];
  if (invoiceCustomerFilter)
    invoiceBaseConditions.push(invoiceCustomerFilter);
  const statusRows = await db.select({
    status: invoices.status,
    count: sql`count(${invoices.id})`,
    amount: sql`coalesce(sum(${invoices.totalAmount}), 0)`,
    paidAmount: sql`coalesce(sum(${invoices.paidAmount}), 0)`,
    pendingAmount: sql`coalesce(sum(${invoices.pendingAmount}), 0)`
  }).from(invoices).where(invoiceCustomerFilter).groupBy(invoices.status);
  const statusCounts = {
    UNPAID: { count: 0, amount: 0 },
    PARTIAL: { count: 0, amount: 0 },
    PAID: { count: 0, amount: 0 },
    VOID: { count: 0, amount: 0 }
  };
  for (const row of statusRows) {
    statusCounts[row.status] = {
      count: Number(row.count),
      amount: money(row.amount)
    };
  }
  const invoiceTotals = statusRows.reduce((total, row) => {
    if (row.status === "VOID") {
      return total;
    }
    return {
      invoiceTotal: money(total.invoiceTotal + Number(row.amount)),
      paidAmount: money(total.paidAmount + Number(row.paidAmount)),
      pendingAmount: money(total.pendingAmount + Number(row.pendingAmount))
    };
  }, { invoiceTotal: 0, paidAmount: 0, pendingAmount: 0 });
  const paymentConditions = [
    gte(payments.paymentDate, month.startDate),
    lte(payments.paymentDate, month.endDate),
    ne(invoices.status, "VOID")
  ];
  if (invoiceCustomerFilter)
    paymentConditions.push(invoiceCustomerFilter);
  const [paymentTotals] = await db.select({ receivedAmount: sql`coalesce(sum(${payments.amount}), 0)` }).from(payments).innerJoin(invoices, eq(invoices.id, payments.invoiceId)).where(and(...paymentConditions));
  const ageBucket = sql`
    case
      when max(0, cast(julianday(${query.date}) - julianday(${invoices.endDate}) as integer)) <= 30 then '0-30 Days'
      when max(0, cast(julianday(${query.date}) - julianday(${invoices.endDate}) as integer)) <= 60 then '31-60 Days'
      when max(0, cast(julianday(${query.date}) - julianday(${invoices.endDate}) as integer)) <= 90 then '61-90 Days'
      else '>90 Days'
    end
  `;
  const agingRows = await db.select({
    label: ageBucket,
    count: sql`count(${invoices.id})`,
    amount: sql`coalesce(sum(${invoices.pendingAmount}), 0)`
  }).from(invoices).where(and(...invoiceBaseConditions, gt(invoices.pendingAmount, 0))).groupBy(ageBucket);
  const agingBuckets = [
    { label: "0-30 Days", count: 0, amount: 0 },
    { label: "31-60 Days", count: 0, amount: 0 },
    { label: "61-90 Days", count: 0, amount: 0 },
    { label: ">90 Days", count: 0, amount: 0 }
  ];
  for (const row of agingRows) {
    const bucket = agingBuckets.find((item) => item.label === row.label);
    if (!bucket)
      continue;
    bucket.count = Number(row.count);
    bucket.amount = money(row.amount);
  }
  const recentEntries = await db.select({
    id: dailyEntries.id,
    customerId: dailyEntries.customerId,
    customerName: customers.name,
    productId: dailyEntries.productId,
    productName: products.name,
    unit: dailyEntries.unit,
    quantity: dailyEntries.quantity,
    session: dailyEntries.session,
    entryDate: dailyEntries.entryDate,
    price: dailyEntries.price,
    amount: sql`${dailyEntries.quantity} * ${dailyEntries.price}`,
    createdAt: dailyEntries.createdAt
  }).from(dailyEntries).innerJoin(customers, eq(customers.id, dailyEntries.customerId)).innerJoin(products, eq(products.id, dailyEntries.productId)).where(customerFilter).orderBy(desc(dailyEntries.entryDate), desc(dailyEntries.id)).limit(5);
  const recentInvoices = await db.select({
    id: invoices.id,
    customerId: invoices.customerId,
    customerName: customers.name,
    invoiceNumber: invoices.invoiceNumber,
    startDate: invoices.startDate,
    endDate: invoices.endDate,
    totalAmount: invoices.totalAmount,
    paidAmount: invoices.paidAmount,
    pendingAmount: invoices.pendingAmount,
    status: invoices.status,
    pdfUrl: invoices.pdfUrl,
    createdAt: invoices.createdAt
  }).from(invoices).innerJoin(customers, eq(customers.id, invoices.customerId)).where(invoiceCustomerFilter).orderBy(desc(invoices.createdAt), desc(invoices.id)).limit(5);
  const recentPayments = await db.select({
    id: payments.id,
    invoiceId: payments.invoiceId,
    invoiceNumber: invoices.invoiceNumber,
    customerId: invoices.customerId,
    customerName: customers.name,
    amount: payments.amount,
    paymentDate: payments.paymentDate,
    paymentMethod: payments.paymentMethod,
    notes: payments.notes,
    createdAt: payments.createdAt
  }).from(payments).innerJoin(invoices, eq(invoices.id, payments.invoiceId)).innerJoin(customers, eq(customers.id, invoices.customerId)).where(invoiceCustomerFilter).orderBy(desc(payments.paymentDate), desc(payments.id)).limit(5);
  return {
    date: query.date,
    month: query.month,
    customerId: query.customerId ?? null,
    totalCustomers: Number(customerTotals?.totalCustomers ?? 0),
    dailySales: money(entryTotals?.dailyAmount),
    monthlyRevenue: money(entryTotals?.monthlyAmount),
    pendingPayments: money(invoiceTotals.pendingAmount),
    invoiceTotal: money(invoiceTotals.invoiceTotal),
    paidAmount: money(invoiceTotals.paidAmount),
    paymentReceived: money(paymentTotals?.receivedAmount),
    daily: {
      totalAmount: money(entryTotals?.dailyAmount),
      entryCount: Number(entryTotals?.dailyEntryCount ?? 0),
      customerCount: Number(entryTotals?.dailyCustomerCount ?? 0)
    },
    monthly: {
      startDate: month.startDate,
      endDate: month.endDate,
      totalAmount: money(entryTotals?.monthlyAmount),
      entryCount: Number(entryTotals?.monthlyEntryCount ?? 0),
      customerCount: Number(entryTotals?.monthlyCustomerCount ?? 0)
    },
    invoiceStatusCounts: statusCounts,
    paymentAging: agingBuckets,
    recentEntries: recentEntries.map((entry) => ({ ...entry, amount: money(entry.amount) })),
    recentInvoices,
    recentPayments
  };
}
async function getCustomerLedgerReport(query, authUser) {
  const fallbackRange = monthRange(today().slice(0, 7));
  const startDate = query.startDate ?? fallbackRange.startDate;
  const endDate = query.endDate ?? fallbackRange.endDate;
  const customerId = authUser.role === "CUSTOMER" ? authUser.customerId : query.customerId;
  if (!customerId) {
    throw new HTTPException(authUser.role === "CUSTOMER" ? 403 : 400, {
      message: authUser.role === "CUSTOMER" ? "Customer account is not linked to a customer profile" : "Customer is required for customer ledger"
    });
  }
  const [customer] = await db.select().from(customers).where(eq(customers.id, customerId)).limit(1);
  if (!customer) {
    throw new HTTPException(404, { message: "Customer not found" });
  }
  const entryConditions = [gte(dailyEntries.entryDate, startDate), lte(dailyEntries.entryDate, endDate)];
  entryConditions.push(eq(dailyEntries.customerId, customerId));
  const entries = await db.select({
    id: dailyEntries.id,
    customerId: dailyEntries.customerId,
    customerName: customers.name,
    productId: dailyEntries.productId,
    productName: products.name,
    unit: dailyEntries.unit,
    quantity: dailyEntries.quantity,
    session: dailyEntries.session,
    entryDate: dailyEntries.entryDate,
    price: dailyEntries.price,
    amount: sql`${dailyEntries.quantity} * ${dailyEntries.price}`,
    createdAt: dailyEntries.createdAt
  }).from(dailyEntries).innerJoin(customers, eq(customers.id, dailyEntries.customerId)).innerJoin(products, eq(products.id, dailyEntries.productId)).where(and(...entryConditions)).orderBy(desc(dailyEntries.entryDate), desc(dailyEntries.id));
  const productTotals = await db.select({
    productId: dailyEntries.productId,
    productName: products.name,
    unit: dailyEntries.unit,
    quantity: sql`coalesce(sum(${dailyEntries.quantity}), 0)`,
    amount: sql`coalesce(sum(${dailyEntries.quantity} * ${dailyEntries.price}), 0)`
  }).from(dailyEntries).innerJoin(products, eq(products.id, dailyEntries.productId)).where(and(...entryConditions)).groupBy(dailyEntries.productId, products.name, dailyEntries.unit).orderBy(products.name);
  const invoiceConditions = [
    eq(invoices.customerId, customerId),
    ne(invoices.status, "VOID"),
    lte(invoices.startDate, endDate),
    gte(invoices.endDate, startDate)
  ];
  const relatedInvoices = await db.select({
    id: invoices.id,
    customerId: invoices.customerId,
    customerName: customers.name,
    invoiceNumber: invoices.invoiceNumber,
    startDate: invoices.startDate,
    endDate: invoices.endDate,
    totalAmount: invoices.totalAmount,
    paidAmount: invoices.paidAmount,
    pendingAmount: invoices.pendingAmount,
    status: invoices.status,
    pdfUrl: invoices.pdfUrl,
    createdAt: invoices.createdAt
  }).from(invoices).innerJoin(customers, eq(customers.id, invoices.customerId)).where(and(...invoiceConditions)).orderBy(desc(invoices.createdAt), desc(invoices.id));
  const billedEntryIds = new Set;
  for (const invoice of relatedInvoices) {
    for (const entry of entries) {
      if (entry.entryDate >= invoice.startDate && entry.entryDate <= invoice.endDate) {
        billedEntryIds.add(entry.id);
      }
    }
  }
  const totalAmount = money(entries.reduce((total, entry) => total + Number(entry.amount), 0));
  const billedAmount = money(entries.reduce((total, entry) => billedEntryIds.has(entry.id) ? total + Number(entry.amount) : total, 0));
  const invoiceTotal = money(relatedInvoices.reduce((total, invoice) => total + invoice.totalAmount, 0));
  const paidAmount = money(relatedInvoices.reduce((total, invoice) => total + invoice.paidAmount, 0));
  const pendingAmount = money(relatedInvoices.reduce((total, invoice) => total + invoice.pendingAmount, 0));
  return {
    customer,
    startDate,
    endDate,
    entries: entries.map((entry) => ({
      ...entry,
      amount: money(entry.amount),
      isBilled: billedEntryIds.has(entry.id)
    })),
    productTotals: productTotals.map((item) => ({
      ...item,
      quantity: quantity(item.quantity),
      amount: money(item.amount)
    })),
    totalAmount,
    billedAmount,
    unbilledAmount: money(totalAmount - billedAmount),
    invoiceSummary: {
      invoiceTotal,
      paidAmount,
      pendingAmount,
      invoiceCount: relatedInvoices.length
    },
    invoices: relatedInvoices
  };
}

// src/validators/reports.ts
var dashboardQuerySchema = exports_external.object({
  date: dateSchema.default(today),
  month: monthSchema.default(() => today().slice(0, 7)),
  customerId: idSchema.optional()
});
var dailySalesQuerySchema = exports_external.object({
  date: dateSchema.default(today)
});
var monthlySalesQuerySchema = exports_external.object({
  month: monthSchema
});
var customerSummaryQuerySchema = exports_external.object({
  customerId: idSchema.optional()
});
var customerLedgerQuerySchema = exports_external.object({
  customerId: idSchema.optional(),
  startDate: dateSchema.optional(),
  endDate: dateSchema.optional()
}).refine((value) => !value.startDate || !value.endDate || value.startDate <= value.endDate, {
  message: "Start date must be before or equal to end date",
  path: ["endDate"]
});

// src/routes/reports.ts
var reportRoutes = new Hono2;
reportRoutes.use("*", requireAuth);
reportRoutes.get("/dashboard", requireRole("ADMIN"), validateQuery(dashboardQuerySchema), async (c) => {
  const query = c.get("validatedQuery");
  return ok(c, await getDashboardReport(query));
});
reportRoutes.get("/daily-sales", requireRole("ADMIN"), validateQuery(dailySalesQuerySchema), async (c) => {
  const query = c.get("validatedQuery");
  return ok(c, await getDailySalesReport(query));
});
reportRoutes.get("/monthly-sales", requireRole("ADMIN"), validateQuery(monthlySalesQuerySchema), async (c) => {
  const query = c.get("validatedQuery");
  return ok(c, await getMonthlySalesReport(query));
});
reportRoutes.get("/customer-summary", requireRole("ADMIN"), validateQuery(customerSummaryQuerySchema), async (c) => {
  const query = c.get("validatedQuery");
  return ok(c, await getCustomerSummaryReport(query));
});
reportRoutes.get("/customer-ledger", validateQuery(customerLedgerQuerySchema), async (c) => {
  const authUser = c.get("user");
  const query = c.get("validatedQuery");
  return ok(c, await getCustomerLedgerReport(query, authUser));
});

// src/app.ts
var app = new Hono2;
app.use("*", logger());
app.use("*", cors({
  origin: env.corsOrigin === "*" ? "*" : env.corsOrigin.split(",").map((origin) => origin.trim()),
  allowHeaders: ["Content-Type", "Authorization"],
  allowMethods: ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"]
}));
app.get("/", (c) => c.redirect("/docs"));
app.get("/api", (c) => c.redirect("/docs"));
app.get("/api/", (c) => c.redirect("/docs"));
app.get("/health", (c) => ok(c, { status: "ok" }));
app.get("/openapi.json", (c) => c.json(openApiDocument));
app.get("/docs", middleware({ url: "/openapi.json" }));
app.route("/auth", authRoutes);
app.route("/products", productRoutes);
app.route("/customers", customerRoutes);
app.route("/entries", entryRoutes);
app.route("/invoices", invoiceRoutes);
app.route("/payments", paymentRoutes);
app.route("/reports", reportRoutes);
app.notFound((c) => fail(c, "Route not found", 404));
app.onError((error51, c) => {
  if (error51 instanceof HTTPException) {
    return fail(c, error51.message, error51.status);
  }
  console.error(error51);
  return fail(c, "Internal server error", 500);
});

